SELECT audit_id, audit_date, audit_result, auditor_id, comments, audit_type, standard_reference
FROM compliance_audits
WHERE product_id = 1;

SELECT * 
FROM testing_protocols 
WHERE spec_id = 1;

SELECT * 
FROM specifications 
WHERE product_id = (SELECT product_id FROM products WHERE product_name = 'DC-DC Converter');

SELECT MAX(typ_value) AS max_val, MIN(typ_value) AS min_val
FROM specifications
WHERE product_id = 1 AND spec_id = 1;

SELECT specification, criticality
FROM specifications
WHERE criticality = 'High';

SELECT t.tester_name, p.product_name, s.specification
FROM testers t, products p, specifications s
WHERE t.tester_id = 0 AND p.product_id = 0 AND s.spec_id = 0;

SELECT product_name
FROM products
WHERE product_id NOT IN (SELECT product_id FROM testing_protocols);

SELECT COUNT(*) 
FROM specifications 
WHERE product_id = 1;
